package kotlinx.coroutines

import org.junit.Test
import kotlin.test.assertTrue
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

class DelayDurationCoercionTest : TestBase() {

    @Test
    fun testDelayDurationCoercion() = runBlocking {
        // Use Dispatchers.Default to ensure we are using real system time and threads
        withContext(Dispatchers.Default) {
            val expectedDuration = 998.milliseconds + 902752.nanoseconds

            // Repeat a few times to ensure consistency
            repeat(5) {
                val start = TimeSource.Monotonic.markNow()
                delay(expectedDuration)
                val actualDuration = start.elapsedNow()
                val difference = actualDuration - expectedDuration

                // We expect the delay to be at least the requested duration.
                // If it's slightly less due to measurement precision, it might be acceptable,
                // but here we are testing for millisecond truncation which causes ~0.9ms error.
                // We use a small tolerance for measurement noise if any, but -0.9ms should definitely fail.

                assertTrue(difference >= -100.nanoseconds, 
                    "Delay was too short! Actual: $actualDuration, Expected: $expectedDuration, Diff: $difference")
            }
        }
    }
}
"}

